// Extract operation and parameters from incoming request
const operation = $json.operation;
const params = $json.parameters || {};
const userId = $json.userId;
const n8nWorkflowId = $workflow.id;
const n8nExecutionId = $execution.id;

console.log('🔷 Hyperliquid Adapter - Operation:', operation);
console.log('Parameters:', params);
console.log('User ID:', userId);

if (!operation) {
  throw new Error('Missing operation parameter');
}

if (!userId) {
  throw new Error('Missing userId parameter');
}

// Map operation to backend endpoint
const operationEndpoints = {
  'placeOrder': 'place-order',
  'cancelOrder': 'cancel-order',
  'cancelAllOrders': 'cancel-all-orders',
  'modifyOrder': 'modify-order',
  'closePosition': 'close-position',
  'updateLeverage': 'update-leverage'
};

const endpoint = operationEndpoints[operation];

if (!endpoint) {
  throw new Error(`Unknown operation: ${operation}`);
}

return {
  operation,
  endpoint,
  userId,
  params: {
    ...params,
    userId,
    n8nWorkflowId,
    n8nExecutionId
  },
  timestamp: Date.now()
};

// Normalize response from backend
const response = $json;

if (!response.success) {
  throw new Error(response.error || 'Operation failed');
}

const result = response.data;

console.log('✅ Hyperliquid operation successful');
console.log('Result:', result);

return {
  success: true,
  operation: $node['Prepare Request'].json.operation,
  userId: $node['Prepare Request'].json.userId,
  result: result,
  timestamp: response.timestamp || Date.now(),
  executionId: $execution.id
};
